// Mapperly (source generator) — NuGet: Riok.Mapperly
[Mapper]
public partial class OrderMapper
{
    // Tự generate implementation:
    public partial OrderDto ToDto(Order source);
    public partial IQueryable<OrderDto> ProjectToDto(IQueryable<Order> q); // EF Core projection!

    // Custom mapping với [MapProperty]
    [MapProperty(nameof(Order.Customer.Name), nameof(OrderDto.CustomerName))]
    public partial OrderDto ToDtoWithCustomer(Order source);

    // Ignore fields
    [MapperIgnoreTarget(nameof(OrderDto.InternalNote))]
    public partial OrderDto ToPublicDto(Order source);
}

// Usage
var mapper = new OrderMapper();
var dto = mapper.ToDto(order); // generated code: new OrderDto { Id = order.Id, ... }

// EF Core ProjectTo — translate sang SQL SELECT (chỉ columns cần)
var dtos = await db.Orders
    .Where(o => o.Status == "active")
    .ProjectToDto(mapper) // Mapperly generates IQueryable projection
    .ToListAsync();

// Manual mapping (đơn giản, không cần thư viện)
public static OrderDto ToDto(this Order order) => new(
    order.Id, order.Status, order.Total, order.CreatedAt);
